{"content": """"Debug: explore year widgets and try hash-based navigation."""
import json
from playwright.sync_api import sync_playwright

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    page = browser.new_page(viewport={"width": 1920, "height": 1080})

    # Check year widgets
    page.goto("https://csrankings.org/", wait_until="networkidle", timeout=120_000)
    page.wait_for_timeout(5000)

    # Look for custom year elements
    year_els = page.evaluate("""
        () => {
            const els = document.querySelectorAll('[id*=year], [class*=year], [id*=from], [id*=to]');
            return Array.from(els).map(e => ({
                tag: e.tagName, id: e.id, class: e.className, 
                visible: e.offsetParent !== null,
                text: e.textContent.trim().substring(0, 50)
            }));
        }
    """)
    for item in year_els:
        print(item)

    # Also look at what AI sub-fields look like in the taxonomy
    ai_checks = page.evaluate("""
        () => {
            const inputs = document.querySelectorAll('input[type=checkbox]');
            return Array.from(inputs).slice(0, 20).map(e => ({
                id: e.id, name: e.name, checked: e.checked, 
                label: e.closest('td')?.textContent.trim().substring(0, 50) || ''
            }));
        }
    """)
    print("\nCheckboxes:")
    for item in ai_checks:
        print(f"  {item}")

    # Now let's try direct hash navigation
    # Based on URL pattern: #/index?all&us
    # For AI: the fields are typically: ai, vision, mlmining, nlp, ir
    # Let's try: #/fromyear/2020/toyear/2025/index?ai&vision&mlmining&nlp&ir&world
    test_url = "https://csrankings.org/#/fromyear/2020/toyear/2025/index?ai&vision&mlmining&nlp&ir&world"
    page.goto(test_url, wait_until="networkidle", timeout=120_000)
    page.wait_for_timeout(8000)

    print(f"\nFinal URL: {page.url}")

    # Check if ranking table has data
    row_count = page.evaluate("document.querySelectorAll('#ranking tbody tr').length")
    print(f"Ranking rows: {row_count}")

    # Look for SJTU
    sjtu = page.evaluate("""
        () => {
            const rows = document.querySelectorAll('#ranking tbody tr');
            for (const row of rows) {
                if (row.textContent.includes('Shanghai Jiao Tong')) {
                    return row.innerHTML;
                }
            }
            return 'NOT FOUND';
        }
    """)
    print(f"\nSJTU row: {sjtu}")

    browser.close()
