{"content": """"Debug: dismiss shepherd tour, explore hash format for world + AI fields."""
from playwright.sync_api import sync_playwright

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    page = browser.new_page(viewport={"width": 1920, "height": 1080})

    page.goto("https://csrankings.org/", wait_until="networkidle", timeout=120_000)
    page.wait_for_timeout(5000)

    # Dismiss shepherd tour overlay
    page.evaluate("""
        () => {
            // Try to find and close shepherd tour
            const overlay = document.querySelector('.shepherd-modal-overlay-container');
            if (overlay) overlay.remove();
            const step = document.querySelector('.shepherd-element');
            if (step) step.remove();
            // Also try clicking any "Next" or "Done" or dismiss buttons
            const btns = document.querySelectorAll('.shepherd-button, .shepherd-cancel-icon');
            btns.forEach(b => b.click());
        }
    """)
    page.wait_for_timeout(1000)

    # Now check if we can interact with the custom region dropdown
    page.click("#region-selected", timeout=5000)
    page.wait_for_timeout(500)

    # Find the "world" option
    world_opts = page.evaluate("""
        () => {
            const options = document.querySelectorAll('.region-option');
            const results = [];
            for (const o of options) {
                const dv = o.getAttribute('data-value');
                const text = o.textContent.trim();
                if (['world', 'northamerica', 'europe', 'asia'].includes(dv)) {
                    results.push({text, dataValue: dv, visible: o.offsetParent !== null});
                }
            }
            return results;
        }
    """)
    print("Continent options:", world_opts)

    # Click world option
    page.click('.region-option[data-value="world"]', timeout=5000)
    page.wait_for_timeout(3000)

    print(f"After world click URL: {page.url}")
    region_val = page.evaluate("document.querySelector('#regions')?.value")
    print(f"Region select value: {region_val}")

    # Now set year range
    # The year slider is a noUiSlider — need to use its API
    page.evaluate("""
        () => {
            const slider = document.getElementById('year-slider');
            if (slider && slider.noUiSlider) {
                slider.noUiSlider.set([2020, 2025]);
            }
        }
    """)
    page.wait_for_timeout(2000)

    # Check year values
    fy = page.evaluate("document.querySelector('#fromyear')?.value")
    ty = page.evaluate("document.querySelector('#toyear')?.value")
    print(f"fromyear: {fy}, toyear: {ty}")

    # Now click "All off" then "AI" toggle
    all_off = page.query_selector("#all_areas_off")
    if all_off and all_off.is_visible():
        all_off.click()
    else:
        page.evaluate("document.querySelector('#all_areas_off')?.click()")
    page.wait_for_timeout(1000)

    # Click AI toggle
    ai_toggle = page.query_selector("#ai_toggle")
    if ai_toggle and ai_toggle.is_visible():
        ai_toggle.click()
    else:
        page.evaluate("document.querySelector('#ai_toggle')?.click()")
    page.wait_for_timeout(5000)

    print(f"Final URL: {page.url}")

    # Check AI checkboxes
    ai_checked = page.evaluate("""
        () => {
            const ids = ['ai', 'vision', 'mlmining', 'nlp', 'ir'];
            return ids.map(id => ({id, checked: document.getElementById(id)?.checked}));
        }
    """)
    print(f"AI checkboxes: {ai_checked}")

    row_count = page.evaluate("document.querySelectorAll('#ranking tbody tr').length")
    print(f"Ranking rows: {row_count}")

    # Look for SJTU
    sjtu = page.evaluate("""
        () => {
            const rows = document.querySelectorAll('#ranking tbody tr');
            for (const row of rows) {
                if (row.textContent.includes('Shanghai Jiao Tong')) {
                    const tds = row.querySelectorAll('td');
                    return Array.from(tds).map(td => td.textContent.trim());
                }
            }
            return 'NOT FOUND';
        }
    """)
    print(f"SJTU: {sjtu}")

    # Show first 5 rows for reference
    first_rows = page.evaluate("""
        () => {
            const rows = document.querySelectorAll('#ranking tbody tr');
            return Array.from(rows).slice(0, 5).map(r => {
                const tds = r.querySelectorAll('td');
                return Array.from(tds).map(td => td.textContent.trim().substring(0, 60));
            });
        }
    """)
    print(f"First 5 rows: {first_rows}")

    browser.close()
