{"content": """"Debug: refine the interaction — correct AI selection and year slider."""
from playwright.sync_api import sync_playwright

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    page = browser.new_page(viewport={"width": 1920, "height": 1080})

    page.goto("https://csrankings.org/", wait_until="networkidle", timeout=120_000)
    page.wait_for_timeout(5000)

    # Dismiss shepherd tour
    page.evaluate("""
        () => {
            const els = document.querySelectorAll('.shepherd-modal-overlay-container, .shepherd-element');
            els.forEach(e => e.remove());
        }
    """)
    page.wait_for_timeout(500)

    # 1. Set region to world
    page.click("#region-selected")
    page.wait_for_timeout(500)
    page.click('.region-option[data-value="world"]')
    page.wait_for_timeout(3000)

    # 2. Set year range using noUiSlider API
    year_set = page.evaluate("""
        () => {
            const slider = document.getElementById('year-slider');
            if (slider && slider.noUiSlider) {
                slider.noUiSlider.set([2020, 2025]);
                return true;
            }
            return false;
        }
    """)
    print(f"Year slider set: {year_set}")

    # Also need to update the hidden selects and trigger change events
    page.evaluate("""
        () => {
            // Set hidden selects
            const fy = document.getElementById('fromyear');
            const ty = document.getElementById('toyear');
            if (fy) { fy.value = '2020'; fy.dispatchEvent(new Event('change', {bubbles: true})); }
            if (ty) { ty.value = '2025'; ty.dispatchEvent(new Event('change', {bubbles: true})); }
        }
    """)
    page.wait_for_timeout(2000)

    fy = page.evaluate("document.querySelector('#fromyear')?.value")
    ty = page.evaluate("document.querySelector('#toyear')?.value")
    print(f"fromyear: {fy}, toyear: {ty}")

    # 3. Field selection: first "all off", then enable AI sub-fields individually
    # Check what the checkboxes look like including the 'ir' one
    all_checkboxes = page.evaluate("""
        () => {
            const inputs = document.querySelectorAll('input[type=checkbox]');
            return Array.from(inputs).map(e => ({id: e.id, name: e.name, checked: e.checked}));
        }
    """)
    print(f"\nAll checkboxes ({len(all_checkboxes)}):")
    for cb in all_checkboxes:
        if cb['id']:
            print(f"  {cb}")

    # Find the "ir" field — it might be named differently
    ir_like = page.evaluate("""
        () => {
            const inputs = document.querySelectorAll('input[type=checkbox]');
            return Array.from(inputs).filter(e => 
                e.id.includes('ir') || e.name.includes('ir') || 
                e.id.includes('web') || e.id.includes('sigir') || e.id.includes('www')
            ).map(e => ({id: e.id, name: e.name, checked: e.checked}));
        }
    """)
    print(f"\nIR-related checkboxes: {ir_like}")

    browser.close()
