{"content": """"
Playwright script to extract SJTU's AI field ranking data from csrankings.org.

Steps:
  1. Navigate to csrankings.org
  2. Dismiss shepherd tour overlay
  3. Set region to "World" via custom dropdown
  4. Set year range to 2020–2025 via noUiSlider API
  5. Select only AI sub-fields (ai, vision, mlmining, nlp, inforet)
  6. Wait for ranking table to render
  7. Extract SJTU's rank, count, and faculty
  8. Output JSON to stdout
"""

import json
import sys
from playwright.sync_api import sync_playwright


def main():
    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True)
        page = browser.new_page(
            viewport={"width": 1920, "height": 1080},
            user_agent=(
                "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 "
                "(KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36"
            ),
        )

        # ── 1. Navigate ──────────────────────────────────────────────
        page.goto("https://csrankings.org/", wait_until="networkidle", timeout=120_000)
        page.wait_for_timeout(5000)

        # ── 2. Dismiss shepherd tour overlay ──────────────────────────
        page.evaluate("""
            () => {
                document.querySelectorAll(
                    '.shepherd-modal-overlay-container, .shepherd-element'
                ).forEach(el => el.remove());
            }
        """)
        page.wait_for_timeout(500)

        # ── 3. Set region to "World" ──────────────────────────────────
        page.click("#region-selected")
        page.wait_for_timeout(500)
        page.click('.region-option[data-value="world"]')
        page.wait_for_timeout(3000)

        # ── 4. Set year range: 2020–2025 ──────────────────────────────
        #    The visible slider is a noUiSlider widget; the hidden <select>
        #    elements are kept in sync by the site's JS.
        page.evaluate("""
            () => {
                const slider = document.getElementById('year-slider');
                if (slider && slider.noUiSlider) {
                    slider.noUiSlider.set([2020, 2025]);
                }
            }
        """)
        page.wait_for_timeout(2000)

        # ── 5. Select only AI and its sub-fields ──────────────────────
        #    AI group checkboxes: ai, vision, mlmining, nlp, inforet
        #    Strategy: uncheck everything, then check only the AI ones.
        ai_fields = {"ai", "vision", "mlmining", "nlp", "inforet"}

        page.evaluate("""
            (aiFields) => {
                const checkboxes = document.querySelectorAll('input[type=checkbox]');
                for (const cb of checkboxes) {
                    if (!cb.id) continue;
                    const shouldBeChecked = aiFields.includes(cb.id);
                    if (cb.checked !== shouldBeChecked) {
                        cb.click();
                    }
                }
            }
        """, list(ai_fields))
        page.wait_for_timeout(3000)

        # Trigger a hash update to force re-render by clicking an AI
        # parent toggle twice if needed — but the checkbox clicks above
        # should have triggered the site's event handlers.
        # Force a URL hash update to ensure the ranking table refreshes.
        page.evaluate("""
            () => {
                // Trigger the rank function if it exists
                if (typeof rank === 'function') { rank(); }
            }
        """)
        page.wait_for_timeout(5000)

        # ── 6. Wait for ranking table ─────────────────────────────────
        page.wait_for_selector("#ranking tbody tr", state="attached", timeout=30_000)
        page.wait_for_timeout(3000)

        # ── 7. Extract SJTU data ──────────────────────────────────────
        result = page.evaluate("""
            () => {
                const rows = document.querySelectorAll('#ranking tbody tr');
                let rank = 0;
                for (const row of rows) {
                    const tds = row.querySelectorAll('td');
                    if (tds.length === 0) continue;
                    const text = row.textContent;
                    if (text.includes('Shanghai Jiao Tong')) {
                        // Structure: td[rank], td[institution], td[count], td[faculty]
                        const cells = Array.from(tds).map(td => td.textContent.trim());
                        // First cell with a number is rank
                        let r = null, c = null, f = null;
                        let nums = [];
                        for (const cell of cells) {
                            if (cell.includes('Shanghai Jiao Tong')) continue;
                            const n = parseFloat(cell);
                            if (!isNaN(n)) nums.push(n);
                        }
                        if (nums.length >= 3) {
                            r = nums[0]; c = nums[1]; f = nums[2];
                        } else if (nums.length === 2) {
                            c = nums[0]; f = nums[1];
                        }
                        return {rank: r, count: c, faculty: f, cells: cells};
                    }
                }
                return null;
            }
        """)

        if result is None:
            print(json.dumps({"error": "Shanghai Jiao Tong University not found"}),
                  file=sys.stderr)
            browser.close()
            sys.exit(1)

        rank = int(result["rank"]) if result["rank"] is not None else None
        count = result["count"]
        faculty = int(result["faculty"]) if result["faculty"] is not None else None

        final_url = page.url

        output = {
            "final_url": final_url,
            "data": {
                "institution": "Shanghai Jiao Tong University",
                "rank": rank,
                "count": count,
                "faculty": faculty,
            },
        }

        print(json.dumps(output, indent=2))

        browser.close()


if __name__ == "__main__":
    main()
