Playwright script to extract SJTU's AI field ranking data from csrankings.org.

Strategy:
  - CSRankings is entirely client-side rendered and driven by URL hash.
  - Navigate to the base page, wait for initial load, then set the hash
    to encode all filters: year range, AI sub-fields, and world region.
  - Wait for the ranking table to re-render, then extract SJTU's row.
"""

import json
import sys
from playwright.sync_api import sync_playwright


TARGET_HASH = "#/fromyear/2020/toyear/2025/index?ai&vision&mlmining&nlp&inforet&world"


def main():
    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True)
        page = browser.new_page(
            viewport={"width": 1920, "height": 1080},
            user_agent=(
                "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 "
                "(KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36"
            ),
        )

        # ── 1. Navigate and wait for initial load ─────────────────────
        page.goto("https://csrankings.org/", wait_until="domcontentloaded", timeout=120_000)
        page.wait_for_selector("#ranking", state="attached", timeout=60_000)
        page.wait_for_timeout(5000)

        # ── 2. Set the hash to apply all filters at once ──────────────
        #    Fields: ai (Artificial Intelligence), vision (Computer Vision),
        #            mlmining (Machine Learning), nlp (NLP),
        #            inforet (The Web & Information Retrieval)
        #    Region: world
        #    Years:  2020–2025
        page.evaluate(f"window.location.hash = '{TARGET_HASH}'")

        # ── 3. Wait for the table to re-render with filtered data ─────
        page.wait_for_timeout(10000)
        page.wait_for_selector("#ranking tbody tr", state="attached", timeout=30_000)
        page.wait_for_timeout(3000)

        # ── 4. Extract Shanghai Jiao Tong University data ─────────────
        sjtu_data = None
        for attempt in range(5):
            sjtu_data = page.evaluate("""
                () => {
                    const rows = document.querySelectorAll('#ranking tbody tr');
                    for (const row of rows) {
                        const text = row.textContent;
                        if (!text.includes('Shanghai Jiao Tong')) continue;

                        const tds = Array.from(row.querySelectorAll('td'));
                        // Extract numeric values from cells (skip institution cell)
                        const nums = [];
                        for (const td of tds) {
                            const t = td.textContent.trim();
                            if (t.includes('Shanghai Jiao Tong')) continue;
                            const n = parseFloat(t);
                            if (!isNaN(n)) nums.push(n);
                        }
                        // nums = [rank, count, faculty]
                        if (nums.length >= 3) {
                            return {rank: nums[0], count: nums[1], faculty: nums[2]};
                        } else if (nums.length === 2) {
                            return {rank: null, count: nums[0], faculty: nums[1]};
                        }
                        return {raw: tds.map(td => td.textContent.trim())};
                    }
                    return null;
                }
            """)
            if sjtu_data is not None:
                break
            page.wait_for_timeout(3000)

        if sjtu_data is None:
            print(json.dumps({"error": "Shanghai Jiao Tong University not found"}),
                  file=sys.stderr)
            browser.close()
            sys.exit(1)

        final_url = page.url
        browser.close()

        rank = int(sjtu_data["rank"]) if sjtu_data.get("rank") is not None else None
        count = sjtu_data.get("count")
        faculty = int(sjtu_data["faculty"]) if sjtu_data.get("faculty") is not None else None

        output = {
            "final_url": final_url,
            "data": {
                "institution": "Shanghai Jiao Tong University",
                "rank": rank,
                "count": count,
                "faculty": faculty,
            },
        }

        print(json.dumps(output, indent=2))


if __name__ == "__main__":
    main()
